      mode: 'observed_tokens_weighted',
      effectiveWeight,
      routePenalty,
      effortMultiplier,
      observedUsage,
      value: Number((((totalTokens / 1000) || 0.1) * effectiveWeight * routePenalty * effortMultiplier).toFixed(3))
