  return {
    ok: result.status === 0 && !result.error,
    status: result.status ?? null,
    signal: result.signal ?? null,
    stdout: result.stdout ?? '',
    stderr: result.stderr ?? '',
    error,
    timedOut: error?.code === 'ETIMEDOUT',
    timeoutMs,
    command,
    args
  };
